function sn(n){const r=new DataView(n);if(1179937895!==r.getUint32(0,1))throw Error("Not a valid GLB file");let t=12;const o=r.getUint32(t,1);if(1313821514!==r.getUint32(t+4,1))throw Error("First GLB chunk is not JSON");const e=new TextDecoder().decode(new Uint8Array(n,t+8,o)),i=JSON.parse(e);t+=8+o;const a=r.getUint32(t,1);if(5130562!==r.getUint32(t+4,1))throw Error("Second GLB chunk is not BIN");return{json:i,binChunk:new DataView(n,t+8,a)};}export{sn as parseGlbContainer};